import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import "./UserProfile.css";

export default function UserProfile() {
  const [user, setUser] = useState(null);
  const [saved, setSaved] = useState([]);
  const [savedResult, setSavedResult] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("auth_token");

    if (token) {
      const payload = JSON.parse(
        atob(token.split(".")[1].replace(/-/g, "+").replace(/_/g, "/"))
      );
      setUser(payload);
    }

    const savedArticles =
      JSON.parse(localStorage.getItem("savedArticles")) || [];
    setSaved(savedArticles);

    const result = localStorage.getItem("savedResult");
    setSavedResult(result);
  }, []);

  const removeSaved = (slug) => {
    const updated = saved.filter(a => a.slug !== slug);
    setSaved(updated);
    localStorage.setItem("savedArticles", JSON.stringify(updated));
  };

  if (!user) return null;

  return (
    <section className="profile-page">
      <div className="profile-left">
        <img src={user.photo} alt={user.email} className="profile-avatar" />
        <span className="profile-email">{user.email}</span>
      </div>

      {savedResult && (
        <div className="saved-result">
          <h3>შენი ტესტის შედეგი</h3>
          <img
            src={`/images/types/${savedResult}.png`}
            width="120"
            alt={savedResult}
          />
        </div>
      )}

      <div className="saved-section">
        <h3>შენახული სტატიები</h3>

        {saved.map(a => (
          <div key={a.slug} className="saved-item">
            <Link to={`/articles/${a.slug}`}>{a.title}</Link>
            <img
              src="/save1.png"
              className="remove-icon"
              onClick={() => removeSaved(a.slug)}
              alt="remove"
            />
          </div>
        ))}
      </div>
    </section>
  );
}
